function FontPairing() {
  const [text, setText] = React.useState('The quick brown fox jumps over the lazy dog.');
  const pairs = [
    { heading: "'Georgia', serif", body: "'system-ui', sans-serif" },
    { heading: "'Helvetica Neue', sans-serif", body: "'Georgia', serif" },
    { heading: "'Palatino Linotype', serif", body: "'Verdana', sans-serif" }
  ];

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#ffffff', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', color: '#1e293b' }}>
      <h2 style={{ margin: '0 0 12px', fontSize: 18 }}>Font Pairing</h2>
      <input value={text} onChange={e => setText(e.target.value)} style={{ marginBottom: 12, padding: 8, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 14 }} />
      <div style={{ flex: 1, overflow: 'auto' }}>
        {pairs.map((p, i) => (
          <div key={i} style={{ padding: '12px 0', borderBottom: '1px solid #e2e8f0' }}>
            <div style={{ fontFamily: p.heading, fontSize: 20, fontWeight: 700, marginBottom: 4 }}>{text}</div>
            <div style={{ fontFamily: p.body, fontSize: 14, color: '#475569' }}>{text}</div>
            <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 6 }}>Heading: {p.heading} · Body: {p.body}</div>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<FontPairing/>);
